parameters.jsCode:
// Настройка: Имя ноды, откуда пришли данные Google Sheets
const sheetNodeName = 'Get rows with [SYNC] checkbox'; 

// Получаем данные из предыдущих шагов
const sheetItems = $items(sheetNodeName); // Все строки из таблицы
const jiraItems = items; // Текущие входящие данные (задачи из Jira)

const results = [];

for (const jiraItem of jiraItems) {
    const jiraData = jiraItem.json;
    const key = jiraData.key;

    // 1. Находим соответствующую строку в данных из Гугл Таблицы по ключу
    const sheetItem = sheetItems.find(i => i.json['Jira Key'] === key);

    // Если строки нет в таблице (странно, но бывает), пропускаем
    if (!sheetItem) continue;

    const sheetData = sheetItem.json;
    const updates = {};
    let hasChanges = false;

    // --- ПРОВЕРКА 1: НАЗВАНИЕ (Summary) ---
    // Берем новое название, только если оно заполнено в таблице
    const newSummary = sheetData['Новое название'] ? sheetData['Новое название'].toString().trim() : '';
    const currentSummary = jiraData.fields.summary;

    if (newSummary !== '' && newSummary !== currentSummary) {
        updates.summary = newSummary;
        hasChanges = true;
    }

    // --- ПРОВЕРКА 2: МЕТКИ (Labels) ---
    // В таблице: строка "Метка1, Метка2". В Jira: массив ["Метка1", "Метка2"]

    // Парсим метки из таблицы
    let sheetLabels = [];
    if (sheetData['Метки']) {
        sheetLabels = sheetData['Метки'].toString().split(',').map(l => l.trim()).filter(l => l !== '');
    }

    // Получаем метки из Jira (если их нет, берем пустой массив)
    const jiraLabels = jiraData.fields.labels || [];

    // Сортируем для корректного сравнения (чтобы ["A", "B"] было равно ["B", "A"])
    sheetLabels.sort();
    jiraLabels.sort();

    // Сравниваем как строки JSON
    if (JSON.stringify(sheetLabels) !== JSON.stringify(jiraLabels)) {
        updates.labels = sheetLabels; // Jira примет массив строк
        hasChanges = true;
    }

    // --- ПРОВЕРКА 3: ПРИОРИТЕТ (Priority) ---
    // Проверяем, есть ли колонка "Приоритет" или "Priority" в таблице
    // В твоем JSON я не вижу колонку "Приоритет", но если ты её добавишь:
    const sheetPriority = sheetData['Приоритет'] || sheetData['Priority']; 

    if (sheetPriority) {
        const currentPriorityName = jiraData.fields.priority ? jiraData.fields.priority.name : '';

        // Сравниваем названия (например "High" vs "High")
        if (sheetPriority !== currentPriorityName) {
            updates.priority = { "name": sheetPriority };
            hasChanges = true;
        }
    }

    // --- ФИНАЛ: ЕСЛИ ЕСТЬ ИЗМЕНЕНИЯ ---
    if (hasChanges) {
        results.push({
            json: {
                key: key,           // Ключ задачи для обновления
                updateFields: updates, // Объект с изменениями для Jira
                systemId: sheetData['System ID'] // ID строки для снятия галочки
            }
        });
    } else {
        // Если изменений нет, но галочка стояла - нам все равно надо её снять,
        // чтобы не обрабатывать эту строку вечно.
        // Передаем пустой updateFields, чтобы Jira Node его пропустила, но Sheet Node сработала.
        results.push({
            json: {
                key: key,
                updateFields: null, // Флаг "не обновлять Jira"
                systemId: sheetData['System ID']
            }
        });
    }
}

return results;

