// 1. Берем текстовые данные напрямую из ноды "Get an issue"
const issueData = $('Get an issue').first().json;
const fields = issueData.fields || {};
// Собираем комментарии
const cleanedComments = (fields.comment?.comments || []).map(c => ({
  author: c.author?.displayName || "Неизвестно",
  body: c.body,
  created: c.created
}));

// Собираем ссылки на вложения
const attachmentLinks = (fields.attachment || []).map(a => ({
  filename: a.filename,
  mimeType: a.mimeType,
  url: a.content
}));

// 2. Достаем файлы и конвертируем их из файловой системы в Base64
const downloadedFiles = [];
const items = $input.all(); 

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {

      // ИСПРАВЛЕНА СТРОКА 29: правильное название метода и порядок аргументов (индекс, ключ)
      const binaryDataBuffer = await this.helpers.getBinaryDataBuffer(i, key);
      const base64String = binaryDataBuffer.toString('base64');

      downloadedFiles.push({
        filename: item.binary[key].fileName,
        mimeType: item.binary[key].mimeType,
        base64: base64String
      });
    }
  }
}

// 3. Формируем чистый итоговый объект
const cleanData = {
  key: issueData.key || "Неизвестно",
  summary: fields.summary,
  description: fields.description,
  status: fields.status?.name,
  priority: fields.priority?.name,
  issuetype: fields.issuetype?.name,
  project: fields.project?.name,
  assignee: fields.assignee?.displayName || null,
  reporter: fields.reporter?.displayName || null,
  labels: fields.labels || [],
  created: fields.created,
  updated: fields.updated,
  comments: cleanedComments,
  attachments_info: attachmentLinks,
  files_data: downloadedFiles
};
return { json: cleanData };

// 1. Берем текстовые данные напрямую из ноды "Get an issue"
const issueData = $json;
const fields = issueData.fields || {};

// Собираем комментарии
const cleanedComments = (fields.comment?.comments || []).map(c => ({
  author: c.author?.displayName || "Неизвестно",
  body: c.body,
  created: c.created
}));


const cleanData = {
  key: issueData.key || "Неизвестно",
  summary: fields.summary,
  description: fields.description,
  status: fields.status?.name,
  priority: fields.priority?.name,
  issuetype: fields.issuetype?.name,
  project: fields.project?.name,
  assignee: fields.assignee?.displayName || null,
  reporter: fields.reporter?.displayName || null,
  labels: fields.labels || [],
  created: fields.created,
  updated: fields.updated,
  comments: cleanedComments,
};

return { json: cleanData };

const body = $input.first().json.body;

let jql;
if (body.customJql && body.customJql.trim()) {
  jql = body.customJql.trim();
} else {
  const project = body.project;
  const issueTypes = body.issueTypes || ['User Story', 'Задача', 'Ошибка', 'Техдолг'];
  const dateFrom = body.dateFrom;
  const dateTo = body.dateTo;
  const typesList = issueTypes.map(t => '"' + t + '"').join(', ');
  jql = 'project = "' + project + '" AND issuetype in (' + typesList + ')';
  if (dateFrom) jql += ' AND created >= "' + dateFrom + '"';
  if (dateTo) jql += ' AND created <= "' + dateTo + '"';
  if (body.extraConditions && body.extraConditions.trim()) {
    jql += ' AND ' + body.extraConditions.trim();
  }
  jql += ' ORDER BY created ASC';
}

return [{ json: { jql, ...body } }];

const issues = [];

for (const item of $input.all()) {
  const issue = item.json;
  const histories = (issue.changelog && issue.changelog.histories) ? issue.changelog.histories : [];

  const sortedHistories = [...histories].sort((a, b) => new Date(a.created) - new Date(b.created));

  const transitions = [];

  if (sortedHistories.length > 0) {
    const firstStatusChange = sortedHistories[0].items && sortedHistories[0].items.find(i => i.field === 'status');
    if (firstStatusChange) {
      transitions.push({
        status: firstStatusChange.fromString,
        enteredAt: issue.fields && issue.fields.created
      });
    }
  } else {
    transitions.push({
      status: issue.fields && issue.fields.status && issue.fields.status.name,
      enteredAt: issue.fields && issue.fields.created
    });
  }

  for (const history of sortedHistories) {
    for (const change of (history.items || [])) {
      if (change.field === 'status') {
        transitions.push({
          status: change.toString,
          enteredAt: history.created
        });
      }
    }
  }

  issues.push({
    key: issue.key,
    summary: (issue.fields && issue.fields.summary) || '',
    type: (issue.fields && issue.fields.issuetype && issue.fields.issuetype.name) || 'Unknown',
    created: (issue.fields && issue.fields.created) || '',
    currentStatus: (issue.fields && issue.fields.status && issue.fields.status.name) || '',
    transitions
  });
}

return [{ json: { issues, meta: { total: issues.length, fetchedAt: new Date().toISOString() } } }];
